#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define W 2400
#define H 1800

typedef struct { double x, y, z; } Vec;

Vec v(double x, double y, double z) {
    Vec r = {x, y, z};
    return r;
}

double dot(Vec a, Vec b) { return a.x*b.x + a.y*b.y + a.z*b.z; }
Vec sub(Vec a, Vec b) { return v(a.x-b.x, a.y-b.y, a.z-b.z); }
Vec add(Vec a, Vec b) { return v(a.x+b.x, a.y+b.y, a.z+b.z); }
Vec mul(Vec a, double s) { return v(a.x*s, a.y*s, a.z*s); }
Vec norm(Vec a) {
    double l = sqrt(dot(a,a));
    return v(a.x/l, a.y/l, a.z/l);
}

double clamp(double x) { return x < 0 ? 0 : (x > 255 ? 255 : x); }

int main() {
    FILE *f = fopen("reconstructed.ppm", "w");
    fprintf(f, "P3\n%d %d\n255\n", W, H);

    double fov = 900.0;
    double cam_y = 1.5;
    double ground_y = 0.0;
    double d = cam_y - ground_y;

    // Sphere parameters (adjusted to match silhouette)
    Vec sp = v(-0.152, 1.841, -6.522);
    double sr = 1.0;
    Vec sc = v(1.0, 0.2, 0.2);

    // Light
    Vec lp = v(5, 5, 5);

    // Floor checkerboard
    double freq = 1.0;
    double xoff = -1.0;
    double zoff = -1.0;
    int inv = 0;

    for (int y = 0; y < H; y++) {
        for (int x = 0; x < W; x++) {
            double dx = (x - W/2.0) / fov;
            double dy = -(y - H/2.0) / fov;

            Vec dir = norm(v(dx, dy, -1));

            double r, g, b;
            int hit = 0;

            // Sphere intersection
            Vec oc = sub(v(0, cam_y, 0), sp);
            double a = dot(dir, dir);
            double bb = 2 * dot(oc, dir);
            double c = dot(oc, oc) - sr * sr;
            double disc = bb*bb - 4*a*c;

            if (disc > 0) {
                double t = (-bb - sqrt(disc)) / (2 * a);
                if (t > 0.001) {
                    Vec pt = add(v(0, cam_y, 0), mul(dir, t));
                    Vec n = norm(sub(pt, sp));
                    Vec L = norm(sub(lp, pt));
                    double diff = dot(n, L);
                    if (diff < 0) diff = 0;

                    Vec V = mul(dir, -1);
                    Vec Hv = norm(add(L, V));
                    double spec = dot(n, Hv);
                    if (spec < 0) spec = 0;
                    spec = pow(spec, 20);

                    r = clamp(sc.x * (0.2 + 0.8 * diff) * 255 + spec * 200);
                    g = clamp(sc.y * (0.2 + 0.8 * diff) * 255 + spec * 40);
                    b = clamp(sc.z * (0.2 + 0.8 * diff) * 255 + spec * 40);
                    hit = 1;
                }
            }

            if (!hit && dy < 0) {
                // Ground plane
                double t = -(cam_y - ground_y) / dy;
                if (t > 0) {
                    double Z = t;
                    double X = dx * t;

                    int ix = (int)(floor(X * freq + xoff));
                    int iz = (int)(floor(Z * freq + zoff));
                    double col = ((ix + iz + inv) & 1) ? 152.0 : 67.0;

                    // Shadow from sphere
                    Vec pt = add(v(0, cam_y, 0), mul(dir, t));
                    Vec L = norm(sub(lp, pt));
                    Vec oc2 = sub(pt, sp);
                    double sa = dot(L, L);
                    double sb = 2 * dot(oc2, L);
                    double sc_ = dot(oc2, oc2) - sr * sr;
                    double sd = sb*sb - 4*sa*sc_;
                    if (sd > 0) {
                        double st = (-sb - sqrt(sd)) / (2 * sa);
                        if (st > 0.001) {
                            Vec sh_pt = add(pt, mul(L, st));
                            Vec to_light = sub(lp, pt);
                            Vec to_sh = sub(sh_pt, pt);
                            if (dot(to_light, to_sh) > 0 && dot(to_sh, to_sh) < dot(to_light, to_light)) {
                                col *= 0.35;
                            }
                        }
                    }

                    r = g = b = clamp(col);
                    hit = 1;
                }
            }

            if (!hit) {
                // Sky - exact formula from reference
                double ndy = dir.y;
                if (ndy < 0) ndy = 0;
                if (ndy > 0.7071) ndy = 0.7071;
                r = clamp(191.5 - 64.0 * ndy);
                g = clamp(217.1 - 38.4 * ndy);
                b = 255;
            }

            fprintf(f, "%d %d %d\n", (int)r, (int)g, (int)b);
        }
    }

    fclose(f);
    return 0;
}
ENDOFCODE
